(() => {
    "use strict"; document.addEventListener("DOMContentLoaded", function () {
        (() => {
            const e = document.querySelectorAll(".faq__item"); e.forEach(t => { t.querySelector(".faq__item-title").addEventListener("click", function (n) { n.preventDefault(), t.open || e.forEach(e => { e !== t && e.open && (e.open = !1) }), t.open = !t.open }) })

            function initOptionSelector(inputId, optionsContainerId, defaultValue = null) {
                const input = document.getElementById(inputId);
                const optionsContainer = document.getElementById(optionsContainerId);
                const options = optionsContainer.querySelectorAll('.option');

                // Функция для выбора опции
                function selectOption(option) {
                    options.forEach(opt => opt.classList.remove('active'));

                    option.classList.add('active');

                    input.value = option.getAttribute('value');
                }

                // Добавляем обработчики клика на все опции
                options.forEach(option => {
                    option.addEventListener('click', () => {
                        selectOption(option);
                    });
                });

                // Устанавливаем значение по умолчанию
                if (defaultValue !== null) {
                    const defaultOption = optionsContainer.querySelector(`.option[value="${defaultValue}"]`);
                    if (defaultOption) {
                        selectOption(defaultOption);
                    }
                }
            }

            initOptionSelector('plan_id', 'plan_id_options', '1');
        })()


    })

    document.addEventListener('DOMContentLoaded', function () {
        // Создаем наблюдатель
        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    entry.target.classList.add('animate-visible');
                    // Можно отключить наблюдение после появления
                    // observer.unobserve(entry.target);
                }
            });
        }, {
            threshold: 0.1, // Срабатывает когда 10% элемента видно
            rootMargin: '0px 0px -50px 0px' // Срабатывает немного раньше
        });

        // Находим все секции для анимации
        const sectionsToAnimate = document.querySelectorAll('#advantages, #reviews, #price, #faq');

        // Добавляем классы и начинаем наблюдение
        sectionsToAnimate.forEach(section => {
            section.classList.add('scroll-animate');
            observer.observe(section);
        });
    });
})();
$(document).ready(function () {
    $(".owl-carousel").owlCarousel({
        loop: true,
        margin: 10,
        nav: false,
        dots: false,
        autoplay: true,
        autoplayTimeout: 3000,
        autoplayHoverPause: true,
        responsive: {
            0: { items: 1.1 },
            768: { items: 2 },
            1200: { items: 3 }
        }
    });
});
